import{_ as a,o,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Dashboard Exports","description":"","frontmatter":{"title":"Dashboard Exports","slug":"dashboard-exports"},"headers":[],"relativePath":"marketer-hub/dashboard-exports.md","filePath":"marketer-hub/dashboard-exports.md"}'),s={name:"marketer-hub/dashboard-exports.md"};function i(l,e,n,d,h,p){return o(),t("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>There are a few features available on the Branch Dashboard that allow you to export data. These exports are delivered in the form of CSV and email.</p><h2 id="available-dashboard-exports" tabindex="-1">Available Dashboard Exports <a class="header-anchor" href="#available-dashboard-exports" aria-label="Permalink to &quot;Available Dashboard Exports&quot;">​</a></h2><h3 id="report-exports" tabindex="-1">Report Exports <a class="header-anchor" href="#report-exports" aria-label="Permalink to &quot;Report Exports&quot;">​</a></h3><p>Branch Dashboard users have the ability to export data from any of the analytics reports in the dashboard. The Branch Summary Page and each of the product-specific analytics pages (Ads, Journeys, Email) each have an icon that allows you to download a CSV of the data that you are viewing. The resulting CSV will match the time range, compare bys, filters, and data granularity that you have set for the table, as well as all of the columns you have selected. Data is delivered to you immediately via a CSV download.</p><p><em>[Image: 636]</em></p><h3 id="daily-exports" tabindex="-1">Daily Exports <a class="header-anchor" href="#daily-exports" aria-label="Permalink to &quot;Daily Exports&quot;">​</a></h3><p>Branch Daily Exports are the most comprehensive exports offered in the Branch Dashboard. Data is presented at log-level and all <a href="./daily-exports-api.html#daily-exports-fields">available export fields</a> are included in the report.</p><p>Since all available data for a single day is included in the export, the files are very large. For an optimal experience, export data for one day at a time. Once you have selected the day&#39;s data that you would like to export, click &quot;Export All&quot; or click on the download button if you would only like to download a specific topic (or topics). You will receive an email with a link to the data for download when it is available.</p><h3 id="custom-exports" tabindex="-1">Custom Exports <a class="header-anchor" href="#custom-exports" aria-label="Permalink to &quot;Custom Exports&quot;">​</a></h3><p>Custom Exports are the most flexible export feature provided by Branch. Custom exports allow you to specify exactly which metrics are the most useful for your analysis.</p><p>Using the custom exports interface, select your Start and End dates and times and the timezone that you would like the data to be exported in. Then you can select the Topic (Installs, Opens, Custom Events etc.) as well as all of the relevant columns (channels, creatives, ad ids, timestamps etc.) for your export. Select your export type, then click export. We also provide a number of pre-configured exports based on the information that marketers are most often looking for.</p><p>Once your export is complete, you will see it available for download on the Custom Exports page within the dashboard.</p><p>More information is available in our <a href="./dashboard-custom-exports.html">Dashboard Custom Exports Guide</a>. In addition to being able to export this data, we also have the <a href="./custom-exports-api.html">Custom Export API</a>.</p><h2 id="deciding-on-an-export-method" tabindex="-1">Deciding on an Export Method <a class="header-anchor" href="#deciding-on-an-export-method" aria-label="Permalink to &quot;Deciding on an Export Method&quot;">​</a></h2><p>If you are deciding on an Export Method from the dashboard: First think about if you need an aggregate snapshot of the data or are looking for log-level information. Report Exports will provide an aggregate based on the parameters and columns set on the analytics page at the time of download.</p><p>If you are looking for log-level information: Do you need all of the <a href="./daily-exports-api.html#daily-exports-fields">columns that Branch offers</a>? If so, use Daily Exports. If you only need a subset of the columns available or if one of our <a href="./dashboard-custom-exports.html#pre-configured-exports">pre-configured exports</a> will suffice, use Custom Exports.</p><p>Finally, if you would like to provide one of your agencies access to your Branch data, they can export via the Report Exports or Custom Exports when appropriate <a href="./add-manage-users-roles-permissions-access.html">data permissions</a> are granted.</p><h2 id="other-exports" tabindex="-1">Other Exports <a class="header-anchor" href="#other-exports" aria-label="Permalink to &quot;Other Exports&quot;">​</a></h2><p>You also have the ability to export data out of Branch systems via API. For more information on Branch APIs, please visit our <a href="./apis-overview.html"><strong>API Developer Documentation.</strong></a></p>',20)])])}const m=a(s,[["render",i]]);export{u as __pageData,m as default};
